def rank1_approx(u, sigma, v):
    rows, cols = len(u), len(v)
    out = []
    for i in range(rows):
        row = []
        for j in range(cols):
            row.append(u[i] * sigma * v[j])  # 只保留一个主方向，构造 rank-1 近似
        out.append(row)
    return out

# 例：u=[1,1], sigma=4.5, v=[1,1] 近似表达'所有元素一起升高'的主模式
